     1→"use client";
     2→
     3→import { useEffect, useState } from "react";
     4→import { cn } from "@/lib/utils";
     5→import { CheckCircle2, RotateCcw, LayoutDashboard, BrainCircuit, AlertTriangle, XCircle, ArrowRight } from "lucide-react";
     6→import { Button } from "@/components/ui/button";
     7→import { useRouter } from "next/navigation";
     8→import { toast } from "sonner";
     9→import { useLanguageStore } from "@/store/language-store";
    10→
    11→interface AnalysisResult {
    12→    viabilityScore: number;
    13→    classification: string;
    14→    summary: string;
    15→    experts: {
    16→        role: string;
    17→        status: "VALIDATED" | "WARNING" | "CRITICAL";
    18→        analysis: string;
    19→    }[];
    20→    status?: number;
    21→    error?: string;
    22→    nextSteps?: string[];
    23→}
    24→
    25→export function AnalysisResults({
    26→    isActive,
    27→    onReset,
    28→    inputData
    29→}: {
    30→    isActive: boolean;
    31→    onReset: () => void;
    32→    inputData: { text: string; files: any[]; links: string[] };
    33→}) {
    34→    const router = useRouter();
    35→    const { t, currentLang } = useLanguageStore();
    36→    const [step, setStep] = useState(0);
    37→    const [logs, setLogs] = useState<string[]>([]);
    38→    const [showResult, setShowResult] = useState(false);
    39→    const [result, setResult] = useState<AnalysisResult | null>(null);
    40→    const [isDemoMode, setIsDemoMode] = useState(false);
    41→
    42→    // Experts definition with dynamic translations
    43→    const expertsList = [
    44→        { id: "SYS_INGEST", name: (t?.analysis?.experts as any)?.SYS_INGEST || "System Ingestion", role: "Telemetry" },
    45→        { id: "AGT_MA", name: (t?.analysis?.experts as any)?.AGT_MA || "Market Analyst", role: "Sentiment" },
    46→        { id: "AGT_FIN", name: (t?.analysis?.experts as any)?.AGT_FIN || "Financial Model", role: "P&L Projection" },
    47→        { id: "AGT_TECH", name: (t?.analysis?.experts as any)?.AGT_TECH || "Tech Feasibility", role: "Stack Audit" },
    48→        { id: "AGT_LEG", name: (t?.analysis?.experts as any)?.AGT_LEG || "Legal Compliance", role: "Risk Check" },
    49→        { id: "SYS_STRUCT", name: (t?.analysis?.experts as any)?.SYS_STRUCT || "Structuration", role: "Canvas Gen" },
    50→        { id: "SYS_SCORE", name: (t?.analysis?.experts as any)?.SYS_SCORE || "Viability Scoring", role: "Algo V4" },
    51→    ];
    52→
    53→    const getDemoResult = (): AnalysisResult => {
    54→        const d = (t?.analysis as any)?.demoResult;
    55→        return {
    56→            viabilityScore: 88,
    57→            classification: "INCUBATE",
    58→            summary: d?.summary || "Strong market potential detected. The core value proposition aligns with current 'No-Code' trends, but the monetization strategy needs refinement to unlock Series A potential.",
    59→            experts: [
    60→                {
    61→                    role: d?.experts?.strategist?.role || "Product Strategist",
    62→                    status: "VALIDATED",
    63→                    analysis: d?.experts?.strategist?.analysis || "Value proposition is clear and addresses a latent market need."
    64→                },
    65→                {
    66→                    role: d?.experts?.business?.role || "Business Model",
    67→                    status: "WARNING",
    68→                    analysis: d?.experts?.business?.analysis || "CAC/LTV ratio assumes viral growth. Conservative modeling recommended."
    69→                },
    70→                {
    71→                    role: d?.experts?.tech?.role || "Tech Architect",
    72→                    status: "VALIDATED",
    73→                    analysis: d?.experts?.tech?.analysis || "Stack choice (Next.js + Supabase) is optimal for rapid MVP scaling."
    74→                },
    75→            ],
    76→            nextSteps: d?.nextSteps || ["Refine pricing model", "Launch MVP in 4 weeks", "Start community building"]
    77→        };
    78→    };
    79→
    80→    const addLog = (msg: string) => setLogs(prev => [...prev.slice(-6), `> ${msg}`]);
    81→    const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));
    82→
    83→    useEffect(() => {
    84→        if (!isActive) {
    85→            setStep(0);
    86→            setLogs([]);
    87→            setShowResult(false);
    88→            setResult(null);
    89→            setIsDemoMode(false);
    90→            return;
    91→        }
    92→
    93→        const runAnalysis = async () => {
    94→            setIsDemoMode(false);
    95→
    96→            // Step 1: Sequence Start
    97→            addLog(t?.analysis?.logs?.init || "Initialising Sequence...");
    98→            await delay(800);
    99→
   100→            // API Call Trigger
   101→            const apiCall = fetch("/api/analyze", {
   102→                method: "POST",
   103→                headers: { "Content-Type": "application/json" },
   104→                body: JSON.stringify({ ...inputData, lang: currentLang }),
   105→            }).then(async (res) => {
   106→                const data = await res.json();
   107→                if (res.status === 429 || data.error === "QUOTA_EXCEEDED") throw new Error("QUOTA_EXCEEDED");
   108→                if (!res.ok) throw new Error(data.details || "Analysis failed");
   109→                return data;
   110→            });
   111→
   112→            // Animate Experts
   113→            for (let i = 0; i < expertsList.length; i++) {
   114→                setStep(i + 1);
   115→                addLog(`[${expertsList[i].id}] Active: ${expertsList[i].name}...`);
   116→                await delay(300 + Math.random() * 300);
   117→            }
   118→
   119→            addLog(t?.analysis?.logs?.computing || "Computing Viability Matrix...");
   120→
   121→            try {
   122→                const data = await apiCall;
   123→                setResult(data);
   124→            } catch (error: any) {
   125→                console.warn("Analysis API failed:", error);
   126→                if (error.message === "QUOTA_EXCEEDED") {
   127→                    addLog(t?.analysis?.logs?.quotaWarning || "Quota Exceeded");
   128→                    setIsDemoMode(true);
   129→                    setResult(getDemoResult());
   130→                    toast.warning(t?.analysis?.logs?.demoMode || "Demo Mode", {
   131→                        description: t?.analysis?.logs?.demoDesc || "Quota reached"
   132→                    });
   133→                } else {
   134→                    addLog(t?.analysis?.logs?.error || "Critical Error");
   135→                    toast.error(t?.analysis?.logs?.analysisFailed || "Analysis Failed");
   136→                }
   137→            }
   138→
   139→            await delay(500);
   140→            setShowResult(true);
   141→        };
   142→
   143→        runAnalysis();
   144→    }, [isActive, inputData, currentLang, t]);
   145→
   146→    const handleOpenWorkspace = () => {
   147→        if (result) {
   148→            const workspaceData = {
   149→                ...inputData,
   150→                analysis: result,
   151→                timestamp: new Date().toISOString(),
   152→                isDemo: isDemoMode
   153→            };
   154→            localStorage.setItem("k3rn_active_project", JSON.stringify(workspaceData));
   155→        }
   156→        router.push("/workspace");
   157→    };
   158→
   159→    if (!isActive) return null;
   160→
   161→    return (
   162→        <div className="w-full max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-8 duration-700 ease-out">
   163→            {!showResult ? (
   164→                // LOADING STATE (Phoenix Style)
   165→                <div className="bg-[#2F323A] rounded-xl shadow-2xl p-8 border border-white/5 flex flex-col items-center gap-8 min-h-[400px] justify-center relative overflow-hidden">
   166→                    {/* Background Pulse */}
   167→                    <div className="absolute inset-0 bg-[#F75105]/5 animate-pulse" />
   168→
   169→                    <div className="flex flex-col items-center gap-4 z-10">
   170→                        <div className="relative">
   171→                            <BrainCircuit className="w-16 h-16 text-[#F75105] animate-pulse" />
   172→                            <div className="absolute inset-0 bg-[#F75105] blur-xl opacity-20 animate-pulse" />
   173→                        </div>
   174→                        <h2 className="text-xl font-sans font-medium text-white tracking-widest uppercase">
   175→                            {t?.analysis?.title || "Committee Analysis"}
   176→                        </h2>
   177→                    </div>
   178→
   179→                    {/* Progress Bar */}
   180→                    <div className="w-full max-w-md h-1 bg-[#3A3D45] rounded-full overflow-hidden">
   181→                        <div
   182→                            className="h-full bg-[#F75105] transition-all duration-300 ease-out"
   183→                            style={{ width: `${(step / expertsList.length) * 100}%` }}
   184→                        />
   185→                    </div>
   186→
   187→                    {/* Console Logs */}
   188→                    <div className="w-full max-w-md h-32 font-mono text-xs text-gray-400 space-y-1.5 p-4 rounded-lg bg-black/20 border border-white/5 overflow-hidden">
   189→                        {logs.map((log, i) => (
   190→                            <p key={i} className="animate-in slide-in-from-left-2 fade-in">
   191→                                {log}
   192→                            </p>
   193→                        ))}
   194→                        <span className="w-2 h-4 bg-[#F75105] animate-blink block mt-1" />
   195→                    </div>
   196→                </div>
   197→            ) : (
   198→                // RESULT STATE (Phoenix Style)
   199→                <div className="bg-[#2F323A] rounded-xl shadow-2xl border-0 overflow-hidden ring-1 ring-white/5 animate-in zoom-in-95 duration-500">
   200→                    <div className="grid md:grid-cols-[280px_1fr] h-full min-h-[500px]">
