    47→                    onFinal?.(event.results[i][0].transcript);
    48→                } else {
    49→                    interimTranscript += event.results[i][0].transcript;
    50→                }
    51→            }
    52→
    53→            if (interimTranscript) {
    54→                onInterim?.(interimTranscript);
    55→            }
    56→        };
